import { Registry } from "../../../core/zc-registry";
export function getStackLayout(spec){
    let { config, data, key, value } = spec;

    if(!data){
        data = this.data;
    }

    let columnInfo_key = this.getColumnByColumnName(key),
        columnInfo_value = this.getColumnByColumnName(value);

        let stack_comp = Registry.getComponent('stackLayout'),
            stack = new stack_comp();

        data.map(series => {
            stack.add(series.data[0], d => d[columnInfo_key.dataindex], d => d[columnInfo_value.dataindex]);
        })

        return stack;
}

Registry.setComponent("stack_layout", getStackLayout);